  @NotNull
  /*package*/ DiffRequest createRequest() {
    RevisionImpl l = (RevisionImpl) getLeftRevision();
    RevisionImpl r = (RevisionImpl) getRightRevision();
    SimpleDiffRequest rq = new SimpleDiffRequest("Title", l.getContent(), r.getContent(), l.getChangeSetName(), r.getChangeSetName());
    ModelDiffViewer.DIFF_SHOW_ROOTID.set(rq, myRoot);
    ModelDiffViewer.DIFF_SHOW_TREE.set(rq, false);
    return rq;
  }

  @Override
  protected Pair<Revision, List<RevisionItem>> calcRevisionsCache() {
    List<LineContent> actualContentMap;
    Revision head;
    try {
      byte[] actualBytes = myActualContent.contentsToByteArray();
      actualContentMap = VCSPersistenceSupport.getLineToContentMap(actualBytes);
      head = new RevisionImpl("HEAD", System.currentTimeMillis(), actualBytes);
    } catch (IOException ex) {
      return Pair.create(errorRevision(ex, null), Collections.<RevisionItem>emptyList());
    } catch (ModelReadException ex) {
      return Pair.create(errorRevision(ex, null), Collections.<RevisionItem>emptyList());
    }
    RootHistoryModel.NodeSet ns = new RootHistoryModel.NodeSet(myRoot);
    RootHistoryModel.ContentRange prevContentRange = buildRanges(ns, actualContentMap);

    List<RevisionItem> items = new ArrayList<RevisionItem>();
    for (VcsFileRevision rev : mySession.getRevisionList()) {
      try {
        byte[] revContent = rev.loadContent();
        List<LineContent> lineToContentMap = VCSPersistenceSupport.getLineToContentMap(revContent);
        RootHistoryModel.ContentRange contentRange = buildRanges(ns, lineToContentMap);
        if (contentRange.isEmpty()) {
          // XXX does this state indicates node addition/removal? I assume so, go on to see if the node is back in earlier revisions. 
          prevContentRange = contentRange;
          continue;
        }
        if (!(contentRange.changedAgainst(prevContentRange))) {
          // ok, no changes, just skip this revision. no need to update prevContentRange as it's the same 
          continue;
        }
        Revision changed = new RevisionImpl(rev.getRevisionNumber().asString(), rev.getRevisionDate().getTime(), revContent);
        items.add(new RevisionItem(changed));
        prevContentRange = contentRange;
      } catch (VcsException ex) {
        // report an exception as an error revision 
        items.add(new RevisionItem(errorRevision(ex, rev)));
      } catch (IOException ex) {
        items.add(new RevisionItem(errorRevision(ex, rev)));
      } catch (ModelReadException ex) {
        items.add(new RevisionItem(errorRevision(ex, rev)));
      }
    }
    return Pair.create(head, items);
  }

  private static RootHistoryModel.ContentRange buildRanges(RootHistoryModel.NodeSet ns, List<LineContent> lineToContentMap) {
    Map<SNodeId, Integer> firstLines = new HashMap<SNodeId, Integer>();
    RootHistoryModel.ContentRange contentRange = new RootHistoryModel.ContentRange();
    int line = 0;
    for (LineContent lc : lineToContentMap) {
      if (lc instanceof NodeLineContent) {
        SNodeId lineNodeId = lc.getNodeId();
        if (ns.isOfInterest(lineNodeId)) {
          Integer start = firstLines.remove(lineNodeId);
          if (start != null) {
            // assume it's the closing NodeLineContent for the same node id 
            // FIXME instead of this assumptions, may want to introduce "closing tag" flag into NodeLineContent to detect start/end of a node range properly 
            contentRange.recordRange(lineNodeId, start, line, lineToContentMap);
          } else {
            // first time we encountered a node of interest, record its start 
            firstLines.put(lineNodeId, line);
          }
        }
      }
      line++;
    }
    // if there were no closing NodeLineContent, assume these records are one-liners 
    for (SNodeId nid : firstLines.keySet()) {
      Integer l = firstLines.get(nid);
      contentRange.recordRange(nid, l, l, lineToContentMap);
    }
    return contentRange;
  }

  private static Revision errorRevision(Exception ex, @Nullable VcsFileRevision rev) {
    return new RevisionImpl(ex.getMessage(), (rev == null ? System.currentTimeMillis() : rev.getRevisionDate().getTime()), null);
  }

